+func statusSeverityFromMessage(msg string) StatusSeverity {
+	msg = strings.TrimSpace(strings.ToLower(msg))
+	if msg == "" {
+		return StatusInfo
+	}
+
+	errorMarkers := []string{
+		"error",
+		"failed",
+		"cannot",
+		"can't",
+		"unable",
+		"invalid",
+		"not found",
+		"denied",
+		"forbidden",
+		"expired",
+		"corrupt",
+		"locked",
+	}
+	for _, marker := range errorMarkers {
+		if strings.Contains(msg, marker) {
+			return StatusError
+		}
+	}
+
+	warnMarkers := []string{
+		"warning",
+		"warn",
+		"cancelled",
+		"canceled",
+		"not configured",
+		"no profile",
+		"no profiles",
+		"no auth",
+		"missing",
+		"ignored",
+	}
+	for _, marker := range warnMarkers {
+		if strings.Contains(msg, marker) {
+			return StatusWarning
+		}
+	}
+
+	successMarkers := []string{
+		"success",
+		"completed",
+		"complete",
+		"activated",
+		"added",
+		"updated",
+		"deleted",
+		"removed",
+		"backed up",
+		"refreshed",
+		"exported",
+		"imported",
+		"saved",
+		"associated",
+		"synced",
+		"connection test:",
+	}
+	for _, marker := range successMarkers {
+		if strings.Contains(msg, marker) {
+			return StatusSuccess
+		}
+	}
+
+	return StatusInfo
 }

