+func normalizeStatusSnapshot(s string) string {
+	plain := ansi.Strip(s)
+	lines := strings.Split(plain, "\n")
+	for i, line := range lines {
+		lines[i] = strings.TrimRight(line, " ")
+	}
+	return strings.Join(lines, "\n")
+}
